import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";

const socket = io("http://localhost:3001");

export default function ChatPage({ currentUser, friend, onBack, onCall }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const [friendTyping, setFriendTyping] = useState(false);
  const messagesEndRef = useRef(null);
  socket.on("chat deleted", ({ chatId }) => {
  setMessages([]); // clear chat window
});


  useEffect(() => {
    socket.emit("register user", currentUser.userId);

    // Load chat history
    fetch(`http://localhost:3001/chat/${currentUser.userId}/${friend.userId}`)
      .then(res => res.json())
      .then(data => setMessages(data));

    socket.on("chat message", (msg) => {
      setMessages(prev => [...prev, msg]);
    });

    socket.on("typing", ({ fromId }) => {
      if (fromId === friend.userId) setFriendTyping(true);
    });

    socket.on("stop typing", ({ fromId }) => {
      if (fromId === friend.userId) setFriendTyping(false);
    });

    socket.on("messages read", ({ chatId }) => {
      setMessages(prev => prev.map(m => ({ ...m, status: "read" })));
    });

    return () => {
      socket.off("chat message");
      socket.off("typing");
      socket.off("stop typing");
      socket.off("messages read");
    };
  }, [currentUser.userId, friend.userId]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = () => {
    if (!input.trim()) return;
    socket.emit("chat message", {
      senderId: currentUser.userId,
      receiverId: friend.userId,
      message: input,
    });
    setInput("");
    socket.emit("stop typing", { fromId: currentUser.userId, toId: friend.userId });
    setTyping(false);
  };
useEffect(() => {
  socket.on("chat deleted", ({ chatId }) => {
    setMessages([]); // clear chat window
  });
  return () => socket.off("chat deleted");
}, []);

  const handleTyping = (e) => {
    setInput(e.target.value);
    if (!typing) {
      setTyping(true);
      socket.emit("typing", { fromId: currentUser.userId, toId: friend.userId });
    }
    if (e.target.value === "") {
      setTyping(false);
      socket.emit("stop typing", { fromId: currentUser.userId, toId: friend.userId });
    }
  };

  const renderTick = (status) => {
    if (status === "sent") return "✓";
    if (status === "delivered") return "✓✓";
    if (status === "read") return "✓✓✔";
    return "";
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <button onClick={onBack} style={styles.backBtn}>←</button>
        <h3>{friend.userId}</h3>
        {friendTyping && <span style={styles.typing}>typing...</span>}
      </div>
<div style={styles.header}>
  <button onClick={onBack} style={styles.backBtn}>←</button>
  <h3>{friend.userId}</h3>
  <button onClick={() => onCall("audio")} style={styles.callBtn}>🎙️ Audio</button>
  <button onClick={() => onCall("video")} style={styles.callBtn}>📹 Video</button>
  {friendTyping && <span style={styles.typing}>typing...</span>}
</div>
<button onClick={() => socket.emit("delete chat", { userA: currentUser.userId, userB: friend.userId })}>
  🗑️ Delete Chat
</button>
<button
  style={styles.deleteBtn}
  onClick={() => socket.emit("delete chat", { userA: currentUser.userId, userB: friend.userId })}
>
  🗑️ Delete Chat
</button>


      <div style={styles.chatBox}>
        {messages.map((msg, i) => (
          <div
            key={i}
            style={{
              ...styles.message,
              alignSelf: msg.senderId === currentUser.userId ? "flex-end" : "flex-start",
              backgroundColor: msg.senderId === currentUser.userId ? "#DCF8C6" : "#FFF",
            }}
          >
            <span>{msg.message}</span>
            <span style={styles.tick}>{renderTick(msg.status)}</span>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div style={styles.inputBox}>
        <input
          style={styles.input}
          value={input}
          onChange={handleTyping}
          placeholder="Type a message"
        />
        <button style={styles.sendBtn} onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    height: "100vh",
    maxWidth: 600,
    margin: "0 auto",
    border: "1px solid #ccc",
    backgroundColor: "#ECE5DD",
  },
  header: {
    display: "flex",
    alignItems: "center",
    padding: 10,
    backgroundColor: "#075E54",
    color: "white",
  },
  backBtn: {
    marginRight: 10,
    background: "none",
    border: "none",
    color: "white",
    fontSize: 20,
    cursor: "pointer",
  },
  callBtn: {
    marginLeft: "auto",
    background: "none",
    border: "none",
    color: "white",
    fontSize: 18,
    cursor: "pointer",
  },
  typing: {
    marginLeft: 10,
    fontStyle: "italic",
    fontSize: 12,
  },
  chatBox: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    padding: 10,
    overflowY: "auto",
  },
  message: {
    margin: 5,
    padding: 10,
    borderRadius: 10,
    maxWidth: "70%",
    wordWrap: "break-word",
    fontSize: 16,
  },
  tick: {
    fontSize: 12,
    marginLeft: 5,
    color: "gray",
  },
  inputBox: {
    display: "flex",
    padding: 10,
    backgroundColor: "#f0f0f0",
  },
  input: {
    flex: 1,
    padding: 10,
    fontSize: 16,
    borderRadius: 20,
    border: "1px solid #ccc",
  },
  sendBtn: {
    marginLeft: 10,
    padding: "10px 20px",
    fontSize: 16,
    borderRadius: 20,
    border: "none",
    backgroundColor: "#25D366",
    color: "white",
    cursor: "pointer",
  },deleteBtn: {
  margin: 10,
  padding: "10px 20px",
  backgroundColor: "#d9534f",
  color: "white",
  border: "none",
  borderRadius: 5,
  cursor: "pointer",
},
};
